    const deleteButton = deleteTarget?.closest<HTMLElement>(`[${FRAME_DELETE_BUTTON_ATTR}="true"]`) || null;

    if (deleteButton && previewRef.current?.contains(deleteButton)) {
      event.preventDefault();
      event.stopPropagation();
      deleteCanvasSelectionEntity(
        deleteButton.getAttribute(FRAME_DELETE_KIND_ATTR),
        deleteButton.getAttribute(FRAME_DELETE_TARGET_ID_ATTR)
      );
      return;
    }

    const target = event.target instanceof HTMLElement ? event.target : null;

    if (textCanvasEditModeActiveRef.current && target && previewRef.current) {
      const clickedTextInput = resolveFrameTextInputElement(target);

      if (clickedTextInput && previewRef.current.contains(clickedTextInput)) {
        const isActiveTextInput = !clickedTextInput.readOnly && document.activeElement === clickedTextInput;

        if (!isActiveTextInput) {
          event.preventDefault();
          focusFrameTextInputForEditing(clickedTextInput);
        }

        return;
      }

      const frameNode =
        resolveFrameSelectionAnchor(target.closest<HTMLElement>(FRAME_SELECTION_NODE_SELECTOR)) ||
        resolveFrameSelectionAnchorAtPoint(
          target.closest<HTMLElement>('.page-inner'),
          event.clientX,
          event.clientY
        );
      const frameGroupId = getFrameGroupId(frameNode);

      if (frameGroupId) {
        focusFrameTextInputForEditingByFrameGroupId(previewRef.current, frameGroupId);
      }
    }

    if (metadataRelationSelectionModeRef.current.kind !== 'idle') {
      event.preventDefault();
      return;
    }

    const choiceButton = target?.closest<HTMLElement>('[role="checkbox"][data-checked]');

    if (!choiceButton) {
      return;
    }

    toggleChoiceBoxElement(choiceButton);
    syncDraftPreviewHtmlRef();
